
CREATE TABLE IF NOT EXISTS public.tenants (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), slug VARCHAR(100) UNIQUE NOT NULL, name VARCHAR(255) NOT NULL, status VARCHAR(50) DEFAULT 'active', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS public.users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, tenant_id UUID NOT NULL REFERENCES public.tenants(id), role VARCHAR(50) NOT NULL, is_active BOOLEAN DEFAULT true, is_verified BOOLEAN DEFAULT false, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS public.audit_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, user_id UUID NOT NULL, action VARCHAR(100) NOT NULL, resource_type VARCHAR(100), resource_id UUID, payload JSONB DEFAULT '{}', ip_address INET, user_agent TEXT, timestamp TIMESTAMPTZ DEFAULT NOW(), is_deleted BOOLEAN DEFAULT FALSE);
CREATE TABLE IF NOT EXISTS public.approvals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), action_id UUID NOT NULL, tenant_id UUID NOT NULL, requested_by UUID NOT NULL, action_type VARCHAR(100) NOT NULL, payload JSONB DEFAULT '{}', risk_score DECIMAL(3,2), risk_factors JSONB DEFAULT '[]', status VARCHAR(50) DEFAULT 'pending', comments TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), decided_at TIMESTAMPTZ, decided_by UUID REFERENCES public.users(id));
